# -*- coding: utf-8 -*-
import csv

questions = [
  {"id":"4259","tipo":"multipla","disciplina":"Matematica","tema":"Funcoes","subtema":"Funcao composta","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Se f(x) = 2x + 1 e g(x) = x^2, entao f(g(3)) e:","alternativa_a":"19","alternativa_b":"7","alternativa_c":"37","alternativa_d":"10","alternativa_e":"49","resposta_correta":"a","explicacao":"g(3) = 3^2 = 9. f(g(3)) = f(9) = 2(9) + 1 = 19.","resposta":""},
  {"id":"4260","tipo":"multipla","disciplina":"Matematica","tema":"Numeros","subtema":"Mmc e mdc","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O MMC (Minimo Multiplo Comum) de 4 e 6 e:","alternativa_a":"12","alternativa_b":"24","alternativa_c":"2","alternativa_d":"6","alternativa_e":"18","resposta_correta":"a","explicacao":"4 = 2^2; 6 = 2 x 3. MMC = 2^2 x 3 = 12.","resposta":""},
  {"id":"4261","tipo":"multipla","disciplina":"Matematica","tema":"Numeros","subtema":"Divisibilidade","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Um numero e divisivel por 3 se:","alternativa_a":"A soma de seus algarismos e divisivel por 3","alternativa_b":"Termina em 3","alternativa_c":"E par","alternativa_d":"Termina em 0 ou 3","alternativa_e":"E maior que 3","resposta_correta":"a","explicacao":"Criterio de divisibilidade por 3: a soma dos algarismos e divisivel por 3. Exemplo: 123 -> 1+2+3=6 (divisivel por 3). 245 -> 2+4+5=11 (nao divisivel). Para 9: a soma dos algarismos e divisivel por 9. Para 2: termina em 0,2,4,6,8. Para 5: termina em 0 ou 5.","resposta":""},
  {"id":"4262","tipo":"multipla","disciplina":"Matematica","tema":"Algebra","subtema":"Valor absoluto em equacoes","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A solucao de |x - 3| = 5 e:","alternativa_a":"x = 8 ou x = -2","alternativa_b":"x = 8 ou x = 2","alternativa_c":"x = -8 ou x = 2","alternativa_d":"x = 3 ou x = 5","alternativa_e":"x = -3 ou x = -5","resposta_correta":"a","explicacao":"|x-3| = 5 => x-3 = 5 (x=8) ou x-3 = -5 (x=-2).","resposta":""},
  {"id":"4263","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Plana","subtema":"Circunferencia e circulo","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O comprimento da circunferencia de raio 7 cm e (pi=3,14):","alternativa_a":"43,96 cm","alternativa_b":"21,98 cm","alternativa_c":"153,86 cm","alternativa_d":"49 cm","alternativa_e":"87,92 cm","resposta_correta":"a","explicacao":"C = 2 x pi x r = 2 x 3,14 x 7 = 43,96 cm.","resposta":""},
  {"id":"4264","tipo":"multipla","disciplina":"Fisica","tema":"Mecanica","subtema":"Colisoes","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"Numa colisao perfeitamente inelastica, os dois corpos:","alternativa_a":"Se unem apos a colisao, conservando o momento linear mas nao a energia cinetica","alternativa_b":"Voltam com as mesmas velocidades (elastica)","alternativa_c":"Conservam tanto o momento quanto a energia cinetica","alternativa_d":"Trocam velocidades completamente","alternativa_e":"Ficam em repouso sempre","resposta_correta":"a","explicacao":"Colisao perfeitamente inelastica: os corpos se unem formando um unico objeto. Conserva-se o momento linear (m1v1 + m2v2 = (m1+m2)vf) mas a energia cinetica nao e conservada (perde-se como calor, som, deformacao). Na colisao perfeitamente elastica, ambos (momento e energia cinetica) se conservam. Na pratica, colisoes sao parcialmente inelasticas.","resposta":""},
  {"id":"4265","tipo":"multipla","disciplina":"Fisica","tema":"Termodinamica","subtema":"Entropia","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"A Segunda Lei da Termodinamica estabelece que:","alternativa_a":"A entropia de um sistema isolado tende a aumentar ou permanecer constante (nunca diminui espontaneamente)","alternativa_b":"A energia total do universo e constante","alternativa_c":"Calor fluiu do corpo mais frio para o mais quente","alternativa_d":"E possivel converter 100% do calor em trabalho","alternativa_e":"Todo processo reversivel tem eficiencia 100%","resposta_correta":"a","explicacao":"A Segunda Lei da Termodinamica tem varias formulacoes equivalentes: (Kelvin-Planck) e impossivel converter todo calor em trabalho; (Clausius) calor flui espontaneamente do quente para o frio; (Entropia) a entropia de um sistema isolado nunca diminui. Entropia mede a desordem/irreversibilidade. A direcao dos processos naturais e sempre no sentido de aumento da entropia total.","resposta":""},
  {"id":"4266","tipo":"multipla","disciplina":"Fisica","tema":"Fisica Moderna","subtema":"Modelo quantico do atomo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"No modelo quantico (orbital) do atomo, os eletrons:","alternativa_a":"Nao tem orbitas definidas — existem em regioes de probabilidade chamadas orbitais","alternativa_b":"Orbitam o nucleo em circulos perfeitos","alternativa_c":"Ficam estacionarios no nucleo","alternativa_d":"Se movem em linhas retas","alternativa_e":"Todos ficam no mesmo nivel de energia","resposta_correta":"a","explicacao":"O modelo quantico (Schrodinger, 1926) substituiu o modelo de Bohr. Eletrons nao tem trajetorias definidas — a funcao de onda (Psi) descreve a probabilidade de encontrar o eletron em cada regiao do espaco (orbital = nuvem de probabilidade). Os numeros quanticos (n, l, ml, ms) descrevem o estado de cada eletron. O Principio da Incerteza de Heisenberg impossibilita trajetorias precisas.","resposta":""},
  {"id":"4267","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Reacoes acido-base","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Na reacao de neutralizacao entre HCl (acido) e NaOH (base), o produto formado e:","alternativa_a":"NaCl (sal) + H2O (agua)","alternativa_b":"H2 (hidrogenio) + NaOH","alternativa_c":"Na + Cl2 + H2O","alternativa_d":"NaO + HCl","alternativa_e":"Na2O + H2 + Cl2","resposta_correta":"a","explicacao":"Neutralizacao: acido + base -> sal + agua. HCl + NaOH -> NaCl + H2O. O H+ do acido se combina com o OH- da base formando agua (neutralizacao). O Na+ e Cl- formam o sal cloreto de sodio (sal de cozinha). Se usadas quantidades equimolares, a solucao resultante e neutra (pH 7).","resposta":""},
  {"id":"4268","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Acidos de Arrhenius","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Segundo Arrhenius, um acido e uma substancia que em agua:","alternativa_a":"Ioniza-se liberando ions H+ (protons)","alternativa_b":"Libera ions OH-","alternativa_c":"Aceita um par de eletrons","alternativa_d":"Doa um par de eletrons","alternativa_e":"Reduz outra substancia","resposta_correta":"a","explicacao":"Arrhenius (1884): acido = substancia que em agua produz H+ (protons). Base = substancia que em agua produz OH-. Acido cloridrico: HCl -> H+ + Cl-. A neutralizacao: H+ + OH- -> H2O. Bronsted-Lowry ampliou: acido = doador de proton (H+); Lewis ampliou mais: acido = receptor de par de eletrons.","resposta":""},
  {"id":"4269","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Organica","subtema":"Aminas","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O grupo funcional das aminas e:","alternativa_a":"-NH2 (grupo amino)","alternativa_b":"-OH (hidroxila)","alternativa_c":"-COOH (carboxila)","alternativa_d":"-CO- (carbonila)","alternativa_e":"-SH (tiol)","resposta_correta":"a","explicacao":"Aminas tem o grupo funcional -NH2 (amina primaria), -NH- (amina secundaria) ou -N- (amina terciaria), derivado da amonia (NH3) com substituicao de um ou mais H por grupos organicos. Sao bases (receptoras de proton de Bronsted-Lowry). Exemplos: metilamina (CH3NH2), anilina (C6H5NH2), aminoacidos (R-CH(NH2)-COOH).","resposta":""},
  {"id":"4270","tipo":"multipla","disciplina":"Biologia","tema":"Citologia","subtema":"Reticulo endoplasmatico","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O reticulo endoplasmatico rugoso (RER) diferencia-se do liso (REL) por:","alternativa_a":"Ter ribossomos associados — sintetiza e modifica proteinas de membrana e secretadas","alternativa_b":"Ser responsavel pela sintese de lipidios","alternativa_c":"Estar presente apenas em celulas vegetais","alternativa_d":"Ter papel na respiracao celular","alternativa_e":"Produzir ATP","resposta_correta":"a","explicacao":"RER: possui ribossomos na superficie citosolica que sintetizam proteinas destinadas a membrana, secretadas ou lisossomos. Essas proteinas entram no lumen do RER para modificacoes (glicosilacao, dobramento). REL: sem ribossomos; sintetiza lipidios (fosfolipidios, esteroides), detoxifica drogas (no figado), armazena Ca++ (no musculo). Ambos fazem parte do sistema de endomembranas.","resposta":""},
  {"id":"4271","tipo":"multipla","disciplina":"Biologia","tema":"Genetica","subtema":"Mutacoes e cancer","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O cancer e causado fundamentalmente por:","alternativa_a":"Acumulo de mutacoes em genes que controlam a divisao celular (proto-oncogenes e supressores tumorais)","alternativa_b":"Infeccao por bacterias patogenicas","alternativa_c":"Deficiencia de vitaminas","alternativa_d":"Envelhecimento do sistema nervoso central","alternativa_e":"Imunidade excessiva do organismo","resposta_correta":"a","explicacao":"Cancer resulta do acumulo de mutacoes (somaticas, nao germinativas) em dois tipos de genes: (1) Proto-oncogenes — ao serem mutados, tornam-se oncogenes que estimulam divisao descontrolada (acelerador quebrado); (2) Genes supressores tumorais (ex: p53, BRCA1) — ao serem inativados, deixam de frear a divisao (freio cortado). Cancer e uma doenca genetica da celula, nao do organismo.","resposta":""},
  {"id":"4272","tipo":"multipla","disciplina":"Biologia","tema":"Ecologia","subtema":"Especies ameacadas","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A principal causa de perda de biodiversidade no mundo atual e:","alternativa_a":"A destruicao e fragmentacao de habitats naturais, principalmente por expansao agricola e urbana","alternativa_b":"A caca predatoria exclusivamente","alternativa_c":"Mudancas climaticas de curto prazo","alternativa_d":"Especies invasoras em todos os biomas","alternativa_e":"Poluicao da agua doce","resposta_correta":"a","explicacao":"A destruicao de habitat (desmatamento, conversao para agricultura, urbanizacao, drenagem de areas umidas) e a principal causa da sexta extincao em massa (Holoceno). Outras causas importantes (em ordem): especies invasoras, superexplotacao (caca/pesca), poluicao, mudancas climaticas. O Brasil lidera o desmatamento absoluto, principalmente na Amazonia e Cerrado.","resposta":""},
  {"id":"4273","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Mercantilismo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O mercantilismo, politica economica predominante nos seculos XVI-XVIII, baseava-se na ideia de que:","alternativa_a":"A riqueza de um Estado era medida pela quantidade de metais preciosos acumulados (bullionismo)","alternativa_b":"O livre comercio entre as nacoes maximizaria a riqueza global","alternativa_c":"A producao industrial era a unica fonte de riqueza","alternativa_d":"O trabalho era a medida do valor das mercadorias","alternativa_e":"A agricultura era a unica fonte de riqueza das nacoes","resposta_correta":"a","explicacao":"O mercantilismo (politica economica dos Estados Absolutos) caracterizou-se por: (1) bullionismo — acumular ouro e prata como riqueza nacional; (2) balanca comercial favoravel (exportar mais que importar); (3) colonialismo — explorar colonias como fornecedoras de materias-primas e mercados; (4) protecionismo — taxas sobre importacoes; (5) forte intervencao estatal na economia.","resposta":""},
  {"id":"4274","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Revolucoes burguesas","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A Revolucao Inglesa (1640-1688) e considerada a primeira revolucao burguesa da historia moderna por:","alternativa_a":"Limitar o poder do rei, fortalecer o parlamento e garantir liberdades civis (Habeas Corpus, Bill of Rights)","alternativa_b":"Implantar a Republica e executar todos os nobres","alternativa_c":"Abolir a monarquia e implantar o socialismo","alternativa_d":"Unificar Inglaterra, Escocia e Gales","alternativa_e":"Conquistar colonies na America do Norte","resposta_correta":"a","explicacao":"A Revolucao Inglesa (Revolucao Puritana + Revolução Gloriosa) estabeleceu o parlamentarismo britanico. Marcos: decapitacao de Carlos I (1649), Protectorado de Cromwell, Restauracao, Bill of Rights (1689) que limitou o poder real e garantiu direitos ao parlamento e aos cidadaos. Inaugurou o constitucionalismo moderno e influenciou as revolucoes francesa e americana.","resposta":""},
  {"id":"4275","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Nazismo","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Adolf Hitler chegou ao poder na Alemanha em:","alternativa_a":"1933, nomeado chanceler pelo presidente Hindenburg","alternativa_b":"1939, com a invasao da Polonia","alternativa_c":"1918, apos a Primeira Guerra Mundial","alternativa_d":"1929, com a crise economica","alternativa_e":"1935, com as Leis de Nuremberg","resposta_correta":"a","explicacao":"Hitler foi nomeado chanceler (primeiro-ministro) da Alemanha em 30 de janeiro de 1933 pelo presidente Paul von Hindenburg, apos o Partido Nazista (NSDAP) ter se tornado o maior partido no Reichstag (33% dos votos em 1932). Hitler usou o incendio do Reichstag (fev. 1933) para obter poderes de emergencia e o Ato de Habilitacao (mar. 1933) para governar por decreto, implantando a ditadura.","resposta":""},
  {"id":"4276","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Descolonizacao na America","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Toussaint L'Ouverture liderou a Revolucao Haitiana (1791-1804), que foi historicamente unica por ser:","alternativa_a":"A unica revolucao bem-sucedida de escravizados na historia — criou a primeira republica negra livre","alternativa_b":"A primeira guerra de independencia na America do Sul","alternativa_c":"Uma revolucao liderada por crioulos brancos","alternativa_d":"Um movimento pacifista de desobediencia civil","alternativa_e":"A primeira independencia da America Central","resposta_correta":"a","explicacao":"A Revolucao Haitiana (1791-1804) foi a maior e mais bem-sucedida revolta de escravizados na historia. Os escravizados africanos e seus descendentes, liderados por Toussaint L'Ouverture e depois Jean-Jacques Dessalines, derrotaram o exercito frances de Napoleao e proclamaram a independencia em 1o de janeiro de 1804. O Haiti tornou-se a primeira Republica Negra livre das Americas e o segundo pais independente do hemisfério.","resposta":""},
  {"id":"4277","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Nordeste — Coronelismo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O coronelismo, pratica politica da Republica Velha brasileira, consistia em:","alternativa_a":"Sistema de dominacao local por grandes proprietarios rurais que controlavam eleitores em troca de favores","alternativa_b":"Controle militar das cidades pelo exercito","alternativa_c":"Sistema de eleicoes diretas supervisionadas por coroneis","alternativa_d":"Alianca entre coroneis e partidos de esquerda","alternativa_e":"Politica de incentivos fiscais para grandes fazendeiros","resposta_correta":"a","explicacao":"O coronelismo (estudado por Victor Nunes Leal em 'Coronelismo, Enxada e Voto') era um sistema de poder local no Brasil rural onde o coronel (grande proprietario) controlava politicamente sua regiao: era intermediario entre o Estado e a populacao rural dependente. Trocava votos (eleitorado cativo) por favores (emprego, saude, protecao). Era parte da 'politica dos governadores' que sustentou a Republica Velha.","resposta":""},
  {"id":"4278","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Semana de Arte Moderna","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A Semana de Arte Moderna de 1922 foi um marco cultural porque:","alternativa_a":"Rompe com o academicismo e lança o Modernismo brasileiro, valorizando a identidade nacional","alternativa_b":"Inaugurou o Realismo no Brasil","alternativa_c":"Foi o inicio do Romantismo brasileiro","alternativa_d":"Apresentou as obras do Parnasianismo ao grande publico","alternativa_e":"Foi uma exposicao de arte europeia importada","resposta_correta":"a","explicacao":"A Semana de Arte Moderna (13-17/02/1922, Teatro Municipal de SP) reuniu artistas, escritores e musicos para romper com o academicismo e o Parnasianismo. Figuras como Mario e Oswald de Andrade, Anita Malfatti, Tarsila do Amaral e Villa-Lobos propunham liberdade formal, experimentacao e valorizacao das raizes brasileiras (depois, o Manifesto Antropofago de 1928 radicalizou a proposta).","resposta":""},
  {"id":"4279","tipo":"multipla","disciplina":"Historia","tema":"Historia do Brasil","subtema":"Ditadura Vargas","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Vargas chegou ao poder em 1930 por meio de:","alternativa_a":"Revolucao de 1930 — movimento armado que depôs Washington Luis e impediu a posse de Julio Prestes","alternativa_b":"Eleicoes democraticas regulares","alternativa_c":"Golpe militar direto sem apoio civil","alternativa_d":"Renuncia voluntaria de Washington Luis","alternativa_e":"Mandato do Congresso Nacional","resposta_correta":"a","explicacao":"A Revolucao de 1930 foi um golpe politico-militar que depos o presidente Washington Luis e impediu a posse do presidente eleito Julio Prestes (SP). Vargas (candidato derrotado, apoiado por Minas Gerais, Rio Grande do Sul e Paraiba — 'Alianca Liberal') foi entronizado pela junta militar. Encerrou a Republica Velha e o sistema cafe-com-leite. Iniciou a Era Vargas (1930-1945 e 1950-1954).","resposta":""},
  {"id":"4280","tipo":"multipla","disciplina":"Geografia","tema":"Energia","subtema":"Energias renovaveis","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"As fontes de energia renovaveis incluem:","alternativa_a":"Solar, eolica, hidraulica, biomassa e geotermica","alternativa_b":"Carvao, gas natural, petroleo e uranio","alternativa_c":"Petroleo, energeia eolica e nuclear","alternativa_d":"Gas natural, solar e derivados de petroleo","alternativa_e":"Carvao mineral, solar e geotermica","resposta_correta":"a","explicacao":"Energias renovaveis: solar (paineis fotovoltaicos e termica), eolica (vento), hidraulica (rios e marés), biomassa (residuos organicos, etanol, biodiesel), geotermica (calor interno da Terra), energia das marees/oceano. As nao-renovaveis sao combustiveis fosseis (carvao, petroleo, gas natural) e uranio (nuclear). O Brasil tem uma das matrizes energeticas mais renovaveis do mundo.","resposta":""},
  {"id":"4281","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Literatura Brasileira","subtema":"Euclides da Cunha","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"'Os Sertoes' (1902), de Euclides da Cunha, e classificado como:","alternativa_a":"Pre-modernismo — obra de transicao que antecipa o Modernismo com sua visao critica da realidade brasileira","alternativa_b":"Parnasianismo","alternativa_c":"Romantismo tardio","alternativa_d":"Realismo puro","alternativa_e":"Simbolismo","resposta_correta":"a","explicacao":"'Os Sertoes' e a principal obra do Pre-modernismo brasileiro. Euclides da Cunha foi como correspondente de guerra a Canudos e produziu uma obra que mescla ciencia (geologia, climatologia, antropologia do seculo XIX) com literatura. A visao do sertanejo como 'rocha viva' da nacionalidade antecipa o interesse modernista pelo Brasil profundo. Euclides criticou a Republica e a campanha de Canudos como crime.","resposta":""},
  {"id":"4282","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Literatura Brasileira","subtema":"Vinicius de Moraes","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Vinicius de Moraes e conhecido na literatura e tambem por:","alternativa_a":"Ser um dos criadores da Bossa Nova, com musicas como 'Garota de Ipanema' (com Tom Jobim)","alternativa_b":"Ter fundado o Tropicalismo","alternativa_c":"Ser o inventor do samba de roda","alternativa_d":"Ter escrito 'A Banda' em parceria com Chico Buarque","alternativa_e":"Ser o compositor de 'Aquarela do Brasil'","resposta_correta":"a","explicacao":"Vinicius de Moraes (1913-1980) foi poeta ('Soneto de Fidelidade'), compositor e letrista. Em parceria com Tom Jobim, criou 'Garota de Ipanema' (1962), uma das musicas mais executadas do mundo, e 'Chega de Saudade' (1958), considerada o marco inaugural da Bossa Nova. Sua obra transita entre a poesia de cunho espiritualizado (fase inicial) e o lirismo erotico-bohemio.","resposta":""},
  {"id":"4283","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Literatura Brasileira","subtema":"Prosa modernista — 1a geracao","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"'Macunaima' (1928), de Mario de Andrade, e um 'heroi sem nenhum carater' que representa:","alternativa_a":"A identidade brasileira plural, contraditoria e miscigenada — uma anti-epopeia nacional","alternativa_b":"O heroi romantico idealizado do Romantismo","alternativa_c":"O camponês nordestino sofrido","alternativa_d":"O trabalhador urbano da industrializacao","alternativa_e":"O colonizador portugues","resposta_correta":"a","explicacao":"'Macunaima, o heroi sem nenhum carater' e uma rapsodica: Mario de Andrade cria um heroi anti-epico que nasce negro, fica branco, e e preguicoso, mentiroso, sensual e adaptavel. Incorpora lendas indigenas, africanas e europeias. A frase 'Ai que preguica!' resume sua essencia. E uma reflexao critica e ludica sobre a identidade nacional brasileira — o povo que improvisa e se adapta a qualquer situacao.","resposta":""},
  {"id":"4284","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Politica","subtema":"Direitos humanos","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A Declaracao Universal dos Direitos Humanos foi adotada pela ONU em:","alternativa_a":"10 de dezembro de 1948","alternativa_b":"26 de junho de 1945","alternativa_c":"10 de dezembro de 1975","alternativa_d":"4 de julho de 1776","alternativa_e":"14 de julho de 1789","resposta_correta":"a","explicacao":"A Declaracao Universal dos Direitos Humanos (DUDH) foi adotada pela Assembleia Geral da ONU em 10/12/1948, em Paris. Contem 30 artigos que estabelecem direitos civis, politicos, economicos, sociais e culturais fundamentais para todos os seres humanos, sem distincao de raca, cor, sexo, lingua, religiao etc. O 10 de dezembro e o Dia Internacional dos Direitos Humanos.","resposta":""},
  {"id":"4285","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Politica","subtema":"Poder e soberania","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Para Hobbes, no estado de natureza a vida humana era:","alternativa_a":"Solitaria, pobre, sordida, bruta e curta — uma guerra de todos contra todos","alternativa_b":"Pacifica e cooperativa","alternativa_c":"Organizada por relacoes de parentesco e tribo","alternativa_d":"Regida pela razao e pela lei natural","alternativa_e":"Justa e igualitaria","resposta_correta":"a","explicacao":"Hobbes, em 'Leviatao' (1651), descreve o estado de natureza como uma condicao de guerra permanente de todos contra todos, onde nao ha propriedade, justica ou arte. 'A vida do homem e solitaria, pobre, sordida, bruta e curta.' Para escapar dessa condicao, os individuos celebram o Contrato Social e cedem seus direitos ao soberano absoluto (o Leviatao), que garante a paz e a ordem.","resposta":""},
  {"id":"4286","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia da Ciencia","subtema":"Ciencia e sociedade","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Robert Merton identificou as normas institucionais da ciencia moderna (CUDOS):","alternativa_a":"Comunismo (conhecimento e publico), Universalismo, Desinteresse e Ceticismo organizado","alternativa_b":"Competicao, Uniao, Dedicacao e Originalidade","alternativa_c":"Criatividade, Utilidade, Disciplina e Objetividade","alternativa_d":"Curiosidade, Universidade, Departamento e Observacao","alternativa_e":"Confirmacao, Utilizacao, Deducao e Observacao","resposta_correta":"a","explicacao":"Merton identificou quatro normas do ethos cientifico (CUDOS): (1) Comunismo/Comunalismo: o conhecimento cientifico e bem publico compartilhado; (2) Universalismo: afirmacoes avaliadas por criterios impessoais, nao por origem do autor; (3) Desinteresse: cientistas devem agir pelo avanco do conhecimento, nao por ganho pessoal; (4) Ceticismo organizado: afirmacoes sujeitadas ao escrutinio critico da comunidade.","resposta":""},
  {"id":"4287","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia do Poder","subtema":"Poder e biopolitica","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"O conceito de biopolitica de Michel Foucault refere-se ao:","alternativa_a":"Poder exercido sobre as populacoes — regulacao e administracao dos processos biologicos da vida","alternativa_b":"Poder dos medicos sobre os pacientes","alternativa_c":"Uso da ciencia biologica para legitimar o Estado","alternativa_d":"Controle genetico das populacoes pelo Estado","alternativa_e":"Politica de saude publica nos hospitais","resposta_correta":"a","explicacao":"Foucault distingue duas formas de poder sobre a vida (biopoder): (1) anátomo-politica do corpo: poder disciplinar sobre corpos individuais (prisons, hospitais, escolas); (2) biopolitica da populacao: regulacao dos processos biologicos da populacao (natalidade, mortalidade, saude, reproducao). O Estado moderno administra a vida biologica das populacoes como estrategia de poder, transformando a politica em gestao da vida.","resposta":""},
  {"id":"4288","tipo":"multipla","disciplina":"Matematica","tema":"Trigonometria","subtema":"Funcao seno e cossenogrande","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"O periodo da funcao f(x) = sen(2x) e:","alternativa_a":"pi","alternativa_b":"2pi","alternativa_c":"pi/2","alternativa_d":"4pi","alternativa_e":"1","resposta_correta":"a","explicacao":"Para f(x) = sen(bx), o periodo T = 2pi/b. Com b=2: T = 2pi/2 = pi.","resposta":""},
  {"id":"4289","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Plana","subtema":"Trigonometria no triangulo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Num triangulo retangulo com cateto oposto = 3 e hipotenusa = 5, o seno do angulo e:","alternativa_a":"3/5","alternativa_b":"4/5","alternativa_c":"3/4","alternativa_d":"5/3","alternativa_e":"4/3","resposta_correta":"a","explicacao":"sen(angulo) = cateto oposto / hipotenusa = 3/5.","resposta":""},
  {"id":"4290","tipo":"multipla","disciplina":"Matematica","tema":"Numeros","subtema":"Multiplos e divisores","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O MDC (Maximo Divisor Comum) de 24 e 36 e:","alternativa_a":"12","alternativa_b":"72","alternativa_c":"6","alternativa_d":"4","alternativa_e":"8","resposta_correta":"a","explicacao":"24 = 2^3 x 3; 36 = 2^2 x 3^2. MDC = produto dos fatores comuns com menor expoente = 2^2 x 3 = 12.","resposta":""},
  {"id":"4291","tipo":"multipla","disciplina":"Fisica","tema":"Mecanica","subtema":"Cinematica — MRU","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"No MRU (Movimento Retilineo Uniforme), a aceleracao e:","alternativa_a":"Nula (zero)","alternativa_b":"Constante e positiva","alternativa_c":"Variavel","alternativa_d":"Negativa sempre","alternativa_e":"Depende da velocidade","resposta_correta":"a","explicacao":"No MRU, a velocidade e constante (em modulo, direcao e sentido). Como a = Delta_v / Delta_t, e a velocidade nao muda (Delta_v = 0), a aceleracao e nula. A posicao varia linearmente com o tempo: x = x0 + v*t.","resposta":""},
  {"id":"4292","tipo":"multipla","disciplina":"Fisica","tema":"Mecanica","subtema":"Cinematica — MRUV","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"No MRUV (Movimento Retilineo Uniformemente Variado), a aceleracao e:","alternativa_a":"Constante (diferente de zero)","alternativa_b":"Nula","alternativa_c":"Proporcional a velocidade","alternativa_d":"Proporcional ao tempo","alternativa_e":"Variavel","resposta_correta":"a","explicacao":"No MRUV, a aceleracao e constante e diferente de zero. A velocidade varia linearmente: v = v0 + a*t. O espaco varia quadraticamente: s = s0 + v0*t + (1/2)*a*t^2. A Equacao de Torricelli: v^2 = v0^2 + 2a*Delta_s.","resposta":""},
  {"id":"4293","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Organica","subtema":"Naftalina e aromaticos","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"O benzeno (C6H6) e a molecula aromatica mais simples. Sua estabilidade especial deve-se a:","alternativa_a":"Deslocalizado dos eletrons pi em todo o anel — ressonancia aromatica (regra de Huckel: 4n+2 eletrons pi)","alternativa_b":"Ligacoes duplas alternadas fixas","alternativa_c":"Isomeria com o ciclohexano","alternativa_d":"Alta polaridade da molecula","alternativa_e":"Reatividade com agua","resposta_correta":"a","explicacao":"O benzeno (Kekule, 1865) nao tem duplas ligacoes alternadas fixas, mas eletrons pi deslocalizados sobre todos os 6 carbonos. Essa deslocalização (ressonancia) da estabilidade extra (energia de ressonancia ~150 kJ/mol). A regra de Huckel: moleculas planares com 4n+2 eletrons pi (n=0,1,2...) sao aromaticas (benzeno: 6 eletrons pi, n=1). Compostos aromaticos fazem preferencialmente substituicao eletrofílica aromatica.","resposta":""},
  {"id":"4294","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Modelos atomicos historicos","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O modelo atomico de Dalton (seculo XIX) propôs que:","alternativa_a":"Os atomos eram esferas macicas e indivisiveis — constituintes fundamentais da materia","alternativa_b":"Os atomos tinham eletrons distribuidos como passas num pudim","alternativa_c":"Os eletrons orbitavam o nucleo em orbitas circulares","alternativa_d":"O nucleo era denso e pequeno, com eletrons ao redor","alternativa_e":"Os eletrons existiam em nuvens de probabilidade","resposta_correta":"a","explicacao":"Dalton (1803-1808): (1) a materia e composta de atomos — esferas macicas indivisiveis e indestrutiveis; (2) atomos do mesmo elemento sao identicos; (3) compostos formam-se pela combinacao de atomos em proporcoes simples. O modelo de Dalton foi superado: Thomson (eletron, pudim de passas), Rutherford (nucleo pequeno e denso), Bohr (orbitas quantizadas), Schrodinger (orbital quantico).","resposta":""},
  {"id":"4295","tipo":"multipla","disciplina":"Biologia","tema":"Fisiologia Humana","subtema":"Termorregulacao","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Os mecanismos de termorregulacao em humanos quando expostos ao calor incluem:","alternativa_a":"Vasodilatacao cutanea, sudorese e reducao da atividade fisica","alternativa_b":"Vasoconstriccao e tremores musculares","alternativa_c":"Piloerecao e metabolismo aumentado","alternativa_d":"Reducao da sudorese e vasoconstriccao","alternativa_e":"Aumento da frequencia respiratoria apenas","resposta_correta":"a","explicacao":"Quando a temperatura corporal sobe: (1) Vasodilatacao cutanea: aumenta o fluxo sanguineo na pele, facilitando a dissipacao de calor por irradiacao e conveccao; (2) Sudorese: a evaporacao do suor resfria a pele (absorcao de calor latente); (3) Reducao da producao de calor (menos atividade muscular). No frio: vasoconstriccao, tremores (calor por contracoes), piloereccao (reduz perda de calor).","resposta":""},
  {"id":"4296","tipo":"multipla","disciplina":"Biologia","tema":"Fisiologia Humana","subtema":"Homeostase","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"Homeostase refere-se a:","alternativa_a":"A manutencao do equilibrio interno do organismo (pH, temperatura, glicemia) por mecanismos de feedback","alternativa_b":"O crescimento e desenvolvimento do organismo","alternativa_c":"A resposta imune a invasores externos","alternativa_d":"O ciclo do sono e vigilia","alternativa_e":"A coordenacao motora pelo cerebelo","resposta_correta":"a","explicacao":"Homeostase e a capacidade do organismo de manter condicoes internas relativamente constantes apesar das mudancas externas. Mecanismos de feedback negativo: glicemia alta -> insulina -> reduz glicemia; temperatura alta -> vasodilatacao/sudorese -> reduz temperatura. O feedback positivo e menos comum (coagulacao sanguinea, contraccoes do parto). Cannon cunhou o termo em 1926.","resposta":""},
  {"id":"4297","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Pos-guerra fria","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Francis Fukuyama propôs o 'Fim da Historia' em 1989 argumentando que:","alternativa_a":"Com o fim da URSS, a democracia liberal seria o modelo politico final e universal da humanidade","alternativa_b":"A historia humana havia acabado com o fim das guerras mundiais","alternativa_c":"O capitalismo seria superado pelo socialismo no seculo XXI","alternativa_d":"A civilizacao ocidental estava em decadencia irreversivel","alternativa_e":"As religies substituiriam a politica como forca organizadora","resposta_correta":"a","explicacao":"Fukuyama, em 'O Fim da Historia e o Ultimo Homem' (1992), argumentou que o fim da Guerra Fria e o colapso do comunismo representavam o 'fim da historia' — nao o fim dos eventos, mas o triunfo definitivo da democracia liberal e do capitalismo de mercado como o modelo final da organizacao politico-economica humana. Essa tese foi amplamente contestada, especialmente apos 11/09, guerras no Oriente Medio e ascensao de regimes autoritarios.","resposta":""},
  {"id":"4298","tipo":"multipla","disciplina":"Historia","tema":"Historia Geral","subtema":"Samuel Huntington","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"Samuel Huntington, em 'O Choque de Civilizacoes' (1996), propôs que os conflitos do pos-guerra fria seriam determinados por:","alternativa_a":"Diferencas culturais e religiosas entre civilizacoes (ocidental, islamica, confuciana, etc.)","alternativa_b":"Disputas economicas por recursos naturais","alternativa_c":"Rivalidades entre superpotencias nucleares","alternativa_d":"Conflitos de classe dentro dos paises","alternativa_e":"Competicao tecnologica entre paises industrializados","resposta_correta":"a","explicacao":"Huntington propôs que, apos o fim da Guerra Fria, as linhas de fratura dos conflitos seriam culturais e religiosas, nao ideologicas. Identificou ~7-8 grandes civilizacoes (ocidental, islamica, sinica/confuciana, ortodoxa, hindu, africana, latino-americana, japonesa). Critica: essencializa culturas, ignora divisoes internas, foi usada para justificar islamofobia. Os atentados de 11/09/2001 aparentemente confirmaram sua tese para muitos analistas.","resposta":""},
  {"id":"4299","tipo":"multipla","disciplina":"Geografia","tema":"Geopolítica","subtema":"Terrorismo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Os atentados de 11 de setembro de 2001 nos Estados Unidos provocaram:","alternativa_a":"A declaracao da 'Guerra ao Terror' pelos EUA, com invasoes do Afeganistao (2001) e Iraque (2003)","alternativa_b":"A criacao da ONU e do Conselho de Seguranca","alternativa_c":"O inicio da Guerra Fria","alternativa_d":"A formacao da OTAN em resposta ao terrorismo","alternativa_e":"A dissolucao da URSS","resposta_correta":"a","explicacao":"Os atentados de 11/09/2001 (Al-Qaeda, Bin Laden) derrubaram as Torres Gemeas e atacaram o Pentagono, matando ~3.000 pessoas. O governo Bush declarou a 'Guerra ao Terror' (GWOT), aprovando o Patriot Act (restricao de liberdades civis), invadindo o Afeganistao (2001, para destruir o Al-Qaeda e os Taleban) e o Iraque (2003, com justificativa falsa de ADM). Reestruturou a geopolitica global do seculo XXI.","resposta":""},
  {"id":"4300","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Gramatica","subtema":"Pronomes relativos","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Em 'O livro que li ontem era excelente', o pronome relativo 'que' substitui:","alternativa_a":"'o livro' — retoma o antecedente livro e inicia oracao adjetiva restritiva","alternativa_b":"'ontem'","alternativa_c":"'excelente'","alternativa_d":"'li'","alternativa_e":"Nao e pronome relativo nesta frase","resposta_correta":"a","explicacao":"'Que' e pronome relativo que retoma o antecedente 'livro' e introduz uma oracao subordinada adjetiva restritiva ('que li ontem' restringe qual livro). Outros pronomes relativos: quem (antecedente pessoa), o qual/a qual (pode substituir que), onde (lugar), cujo (posse). Oracoes adjetivas restritivas limitam/identificam o antecedente (sem virgulas); explicativas acrescentam informacao (com virgulas).","resposta":""},
  {"id":"4301","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Literatura Brasileira","subtema":"Decadentismo e Simbolismo","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A obra 'Canavieira' de Joao do Rio e um exemplo de cronica social que retrata:","alternativa_a":"A vida boêmia, os marginalizados e as ruas do Rio de Janeiro da belle epoque","alternativa_b":"O sertao nordestino","alternativa_c":"A aristocracia imperial brasileira","alternativa_d":"O operariado paulistano","alternativa_e":"A vida religiosa no interior","resposta_correta":"a","explicacao":"Joao do Rio (Paulo Barreto, 1881-1921) foi um cronista urbano que documentou a belle epoque carioca. Em obras como 'A Alma Encantadora das Ruas' (1908), retratou os marginalizados, os artistas, os vagabundos e as transformacoes urbanas do Rio de Janeiro modernizando-se. Introduziu no Brasil a reportagem moderna e a cronica de costumes influenciada pelo flaneur baudelairiano.","resposta":""},
  {"id":"4302","tipo":"multipla","disciplina":"Lingua Portuguesa","tema":"Literatura Brasileira","subtema":"Auto da Compadecida","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"'O Auto da Compadecida' (1955), de Ariano Suassuna, pertence ao movimento:","alternativa_a":"Modernismo — Movimento Armorial — teatro popular nordestino com elementos do folclore e cordel","alternativa_b":"Romantismo tardio","alternativa_c":"Naturalismo","alternativa_d":"Simbolismo","alternativa_e":"Realismo critico","resposta_correta":"a","explicacao":"Ariano Suassuna (1927-2014) fundou o Movimento Armorial (1970), que valorizava a arte popular nordestina (cordel, xilogravura, musica de viola). 'O Auto da Compadecida' e uma peca teatral que mistura o teatro de rua nordestino, o auto religioso medieval, o cordel e personagens tipicos (Joao Grilo, Chico, o bispo, o cangaceiro). E uma obra de arte popular erudita, tipicamente brasileira.","resposta":""},
  {"id":"4303","tipo":"multipla","disciplina":"Filosofia","tema":"Filosofia Medieval","subtema":"Tomas de Aquino","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"A sintese do pensamento de Aristoteles com o cristianismo, realizada por Santo Tomas de Aquino no seculo XIII, ficou conhecida como:","alternativa_a":"Escolastica tomista ou Tomismo","alternativa_b":"Platonismo crista","alternativa_c":"Augustinismo","alternativa_d":"Nominalismo","alternativa_e":"Empirismo medieval","resposta_correta":"a","explicacao":"Santo Tomas de Aquino (1225-1274) realizou a maior sintese filosofico-teologica do seculo XIII na 'Summa Theologiae': integrou a metafisica e a logica aristotelicas a fe crista. Argumentou que razao e fe sao compativeis e complementares — a razao pode demonstrar a existencia de Deus (Cinco Vias). O Tomismo tornou-se a filosofia oficial da Igreja Catolica e continua influente na filosofia analitica contemporanea.","resposta":""},
  {"id":"4304","tipo":"multipla","disciplina":"Sociologia","tema":"Sociologia da Modernidade","subtema":"Modernidade liquida","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Zygmunt Bauman, em 'Modernidade Liquida' (2000), descreve a contemporaneidade como um periodo de:","alternativa_a":"Instabilidade e fluidez das relacoes, identidades e instituicoes — nada e duradouro ou solido","alternativa_b":"Solidez e permanencia das estruturas sociais","alternativa_c":"Retorno ao comunitarismo e aos valores tradicionais","alternativa_d":"Uniformizacao global das culturas","alternativa_e":"Reducao das desigualdades pelo capitalismo","resposta_correta":"a","explicacao":"Bauman contrapoe a 'modernidade solida' (solidas estruturas como o Estado, a familia, o emprego vitalicio) a 'modernidade liquida' contemporanea: tudo flui e se transforma rapidamente. Relacoes sao descartaveis ('amor liquido'), trabalho e precarizado, identidades sao multiplas e fragmentadas, consumismo substitui projetos de vida duradouros. A metafora do liquido captura a incapacidade de manter uma forma.","resposta":""},
  {"id":"4305","tipo":"multipla","disciplina":"Matematica","tema":"Geometria Espacial","subtema":"Piramide","dificuldade":"Medio","fonte":"Vestibular","ano":"2024","enunciado":"Uma piramide de base quadrada com lado 4 cm e altura 3 cm tem volume:","alternativa_a":"16 cm3","alternativa_b":"48 cm3","alternativa_c":"12 cm3","alternativa_d":"64 cm3","alternativa_e":"24 cm3","resposta_correta":"a","explicacao":"V = (1/3) x Area_base x altura = (1/3) x (4x4) x 3 = (1/3) x 16 x 3 = 16 cm3.","resposta":""},
  {"id":"4306","tipo":"multipla","disciplina":"Fisica","tema":"Acustica","subtema":"Ultrassom","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"O ultrassom utilizado na medicina diagnostica baseia-se no principio de:","alternativa_a":"Reflexao de ondas sonoras de alta frequencia nos tecidos, gerando imagens","alternativa_b":"Absorcao de raios-X pelos tecidos","alternativa_c":"Emissao de luz pelos tecidos","alternativa_d":"Ressonancia magnetica nuclear","alternativa_e":"Radioatividade dos tecidos","resposta_correta":"a","explicacao":"O ultrassom medico (ecografia) usa ondas sonoras com frequencia acima de 20.000 Hz (inaudivel para humanos, 2-20 MHz na medicina). As ondas penetram os tecidos e sao refletidas nas interfaces entre tecidos de densidade diferente. O transdutor emite e recebe as ondas; o computador calcula distancias e cria a imagem (ecotomografia). E nao invasivo, sem radiacao ionizante.","resposta":""},
  {"id":"4307","tipo":"multipla","disciplina":"Quimica","tema":"Quimica Geral","subtema":"Diagrama de fases","dificuldade":"Dificil","fonte":"Vestibular","ano":"2024","enunciado":"O ponto triple no diagrama de fases de uma substancia e o ponto onde:","alternativa_a":"As tres fases (solido, liquido e gas) coexistem em equilibrio termodinamico","alternativa_b":"A substancia muda de solido direto para gas (sublimacao)","alternativa_c":"A pressao e temperatura sao maximas para o estado liquido","alternativa_d":"A substancia existe apenas no estado gasoso","alternativa_e":"A densidade e maxima","resposta_correta":"a","explicacao":"O ponto triple e uma temperatura e pressao especificas onde as tres fases de uma substancia coexistem em equilibrio. Para a agua: T = 273,16 K (0,01 graus C) e P = 611,73 Pa (0,006 atm). E o ponto de referencia para a escala Kelvin. Acima do ponto critico (temperatura e pressao criticas), a substancia existe como fluido supercritico, sem fronteira entre liquido e gas.","resposta":""},
  {"id":"4308","tipo":"multipla","disciplina":"Biologia","tema":"Citologia","subtema":"Celula Procariote vs Eucariote","dificuldade":"Facil","fonte":"Vestibular","ano":"2024","enunciado":"A principal diferenca entre celulas procariontes e eucariontes e:","alternativa_a":"Eucariotas tem nucleo membranado (carioteca); procariotas nao tem nucleo definido","alternativa_b":"Procariotas sao maiores que eucariotas","alternativa_c":"Eucariotas nao tem parede celular","alternativa_d":"Procariotas tem mais organelas que eucariotas","alternativa_e":"Eucariotas nao tem membrana plasmatica","resposta_correta":"a","explicacao":"A diferenca fundamental: eucariotas (animais, plantas, fungos, protistas) tem o DNA envolvido por membrana nuclear (carioteca), formando o nucleo verdadeiro. Procariotas (bacterias e arqueas) nao tem membrana nuclear — o DNA fica livre no citoplasma (nucleoide). Eucariotas tambem tem organelas membranosas (mitocondria, complexo de Golgi, RE) ausentes nos procariotas.","resposta":""},
]

